							<$reveal type="nomatch" state=<<diffState>> text="open" tag="span"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 18l6-6-6-6"/></svg></$reveal>
						</$button>
						<$button class="mv-icon-btn mv-icon-btn-danger tc-btn-invisible" tooltip="Delete this snapshot">
							<$action-confirm $message={{{ [[Delete snapshot ']addsuffix<slabel>addsuffix[' from ']addsuffix<tiddlerTitle>addsuffix['?]] }}}>
							<$action-minver op="delete" title=<<tiddlerTitle>> snapshot-id=<<sid>>/>
							</$action-confirm>
							<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>
						</$button>
					</td>
				</tr>
				<$reveal type="match" state=<<diffState>> text="open" tag="tr">
