						<$list filter="[<snapshotsTiddler>get[text]jsonindexes<idx>,[fields]] [<tiddlerTitle>fields[]] +[sort[]]" variable="fieldName">
							<$let
								snapshotVal={{{ [<snapshotsTiddler>get[text]jsonget<idx>,[fields],<fieldName>] +[else[]] }}}
								currentVal={{{ [<tiddlerTitle>get<fieldName>] +[else[]] }}}
								snapshotHasField={{{ [<snapshotsTiddler>get[text]jsonindexes<idx>,[fields]match<fieldName>count[]] }}}
								currentHasField={{{ [<tiddlerTitle>has<fieldName>then[1]else[0]] }}}
							>
							<%if [<snapshotVal>!match<currentVal>] %>
